import{Camera}from"./JS/Camera";import{Drone}from"./JS/Drone";import{Points}from"./JS/points";import{Vector2}from"./JS/Vector2";class Game{#size={width:window.innerWidth,height:window.innerHeight,center:new Vector2({x:window.innerWidth/2,y:window.innerHeight/2}),areaSize:1e3};#minDistBetween=25;#mainCanvas=document.getElementById("main-canvas");#mainCtx=this.#mainCanvas.getContext("2d");#mapCanvas=document.getElementById("map-canvas");#mapCtx=this.#mapCanvas.getContext("2d");#Drone=null;#Camera=null;#debug=!1;constructor(debug=!1){this.#debug=debug,debug&&(this.#size.center.x=this.#size.width/4),this.#mainCanvas.width=debug?this.#size.width/2:this.#size.width,this.#mainCanvas.height=this.#size.height,this.#mapCanvas.width=debug?this.#size.width/2:this.#size.width,this.#mapCanvas.height=this.#size.height,this.#Drone=new Drone(new Vector2(Object.assign({},this.#size.center,{}))),this.#Camera=new Camera({target:this.#Drone,center:new Vector2(Object.assign({},this.#size.center,{}))});const bounds=this.#setBounds();this.locations=this.#generateItems(50,bounds),this.points=this.locations.map((center=>new Points(center)))}#setBounds(){const{center:center,areaSize:areaSize}=this.#size;return{top:center.y-areaSize/2,right:center.x+areaSize/2,left:center.x-areaSize/2,bottom:center.y+areaSize/2}}start(){this.#animate()}#updates(){this.#Drone.update()}#draw(){this.#Drone.draw(this.#mapCtx),this.points.forEach((p=>p.draw(this.#mapCtx)))}#render(fov){this.#Camera.render()}#animate(){const{width:width,height:height}=this.#size;this.#mapCtx.clearRect(0,0,this.#debug?width/2:width,height);this.#updates();this.#draw(),requestAnimationFrame((()=>this.#animate()))}#generateItems(count,bounds){const locations=[];for(let i=0;i<count;i++){const center=new Vector2({x:lerp(bounds.left,bounds.right,Math.random()),y:lerp(bounds.top,bounds.bottom,Math.random())}),centers=locations.map((item=>item.center));centers.push(this.#Drone.getCenter);!centers.find((item=>{if(item)return distance(center,item)<this.#minDistBetween}))&&locations.push(center)}return locations}}function lerp(a,b,t){return a+(b-a)*t}function distance(p1,p2){return Math.hypot(p1.x-p2.x,p1.y-p2.y)}document.addEventListener("DOMContentLoaded",(()=>{new Game(!0).start()}));